import { toServerForms } from '../../server/forms/form.js';
import { toServerItemSections } from '../../server/items/section.js';
import { serializeRawServerFormsValue } from '../forms/value.js';
export const toServerItemInfo = (sonolus, localize, info, creates, searches) => ({
    title: info.title && localize(info.title),
    creates: info.creates && toServerForms(localize, info.creates, creates),
    searches: info.searches && toServerForms(localize, info.searches, searches),
    quickSearchValues: info.quickSearchValue && serializeRawServerFormsValue(info.quickSearchValue, searches),
    sections: toServerItemSections(sonolus, localize, info.sections, searches),
    banner: info.banner,
});
